import{_ as a,o as i,c as o,a3 as t}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.Logging","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/logging.md","filePath":"cosmos/framework/packages/logging.md","lastUpdated":1783216089000}'),r={name:"cosmos/framework/packages/logging.md"};function s(n,e,d,l,g,c){return i(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="xihan-framework-logging" tabindex="-1">XiHan.Framework.Logging <a class="header-anchor" href="#xihan-framework-logging" aria-label="Permalink to &quot;XiHan.Framework.Logging&quot;">​</a></h1><blockquote><p>结构化日志：Serilog 集成、控制台/文件输出、异步写入、结构化与性能日志。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Logging</code></li><li><strong>模块类</strong>：<code>XiHanLoggingModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Logging 在 Serilog 之上封装了一套开箱即用的日志基础设施。启用后自动配置控制台与文件双路输出，文件路借助 <code>Serilog.Sinks.Async</code> 异步写入、按天与按大小滚动。除通用日志外，它还提供结构化日志、性能监控日志与多租户日志上下文等专用接口。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>想一行 <code>[DependsOn]</code> 就获得控制台 + 文件的完整日志配置，无需手写 Serilog 引导代码。</li><li>需要日志文件异步写入、按天滚动、限制文件大小与保留数量。</li><li>需要记录结构化数据、业务事件，或对 API/数据库调用做性能计时。</li><li>需要在日志中自动携带 UserId、TenantId、TraceId 等上下文。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Logging</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanLoggingModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>PreConfigureServices</code> 设置 <code>XiHanLoggingOptions</code> 默认值（启用、最小级别 Information），在 <code>ConfigureServices</code> 中调用 <code>AddXiHanLogging(config)</code>，从配置节 <code>XiHan:Logging</code> 绑定选项并配置 Serilog。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>Serilog 集成</strong>：通过构建器统一配置最小级别、上下文增强与属性丰富化，接入 ASP.NET Core。</li><li><strong>异步文件输出</strong>：借助 <code>Serilog.Sinks.Async</code> 异步写入，按天滚动 + 按大小滚动，限制保留文件数与单文件大小。</li><li><strong>控制台输出</strong>：按日志级别使用不同输出模板。</li><li><strong>结构化日志</strong>：<code>IStructuredLogger</code> 支持键值对、事件、业务动作的结构化记录。</li><li><strong>性能监控</strong>：<code>IPerformanceLogger</code> 记录 API 调用、数据库查询、内存/CPU；<code>IPerformanceTimer</code> 支持 <code>using</code> 自动计时。</li><li><strong>多租户上下文</strong>：<code>ILogContext</code>（Scoped）携带 UserId、TenantId、RequestId、TraceId 等，支持作用域隔离与还原。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>IXiHanLogger</code> / <code>IXiHanLogger&lt;T&gt;</code></td><td>通用日志接口与泛型版本</td></tr><tr><td><code>IStructuredLogger</code></td><td>结构化日志接口（事件、业务动作）</td></tr><tr><td><code>IPerformanceLogger</code> / <code>IPerformanceTimer</code></td><td>性能日志接口与计时器</td></tr><tr><td><code>ILogContext</code></td><td>日志上下文（UserId/TenantId/TraceId 等，支持 Scope）</td></tr><tr><td><code>IXiHanLoggerFactory</code></td><td>日志器工厂</td></tr><tr><td><code>XiHanLoggerConfigurationBuilder</code></td><td>Serilog <code>LoggerConfiguration</code> 的 Fluent 构建器</td></tr><tr><td><code>XiHanFileLoggerProvider</code> / <code>XiHanConsoleLoggerProvider</code></td><td>文件 / 控制台日志提供器</td></tr><tr><td><code>XiHanLoggingOptions</code></td><td>主日志配置（配置节 <code>XiHan:Logging</code>）</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li>内部依赖：仅 <a href="./core">XiHan.Framework.Core</a>。</li><li>第三方核心：<code>Serilog.AspNetCore</code>（含 Serilog 核心与 Console/File sink 传递依赖）、<code>Serilog.Sinks.Async</code>（异步写入）。</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./observability">XiHan.Framework.Observability</a> — 可观测性（追踪/指标）与日志互补。</li></ul>`,20)])])}const p=a(r,[["render",s]]);export{k as __pageData,p as default};
